const proj4 = require('./dist/proj4.js');

const wktSource = 'PROJCS[\"unnamed\",GEOGCS[\"Unknown datum based upon the custom spheroid\",DATUM[\"Not specified (based on custom spheroid)\",SPHEROID[\"Custom spheroid\",6371007.181,0]],PRIMEM[\"Greenwich\",0],UNIT[\"degree\",0.0174532925199433,AUTHORITY[\"EPSG\",\"9122\"]]],PROJECTION[\"Sinusoidal\"],PARAMETER[\"longitude_of_center\",0],PARAMETER[\"false_easting\",0],PARAMETER[\"false_northing\",0],UNIT[\"Meter\",1],AXIS[\"Easting\",EAST],AXIS[\"Northing\",NORTH]]';

const projSource = '+proj=sinu +lon_0=0 +x_0=0 +y_0=0 +R=6371007.181 +units=m +no_defs +type=crs';

const pWKT = proj4(wktSource);
const pProj = proj4(projSource);

// Simulate the transform.forward path for WKT
var pt = { x: -8895604.157333, y: 4447802.078667 };

// Step 1: source.to_meter check  
console.log('WKT to_meter:', pWKT.oProj.to_meter);
// WKT has to_meter=1, so multiply
var step1 = { x: pt.x * 1, y: pt.y * 1 };
console.log('After to_meter:', step1);

// Step 2: source.inverse (sinu -> longlat)
var step2 = pWKT.oProj.inverse(step1);
console.log('After inverse (radians):', step2);

// Step 3: dest is WGS84/longlat, multiply by R2D
var R2D = 180 / Math.PI;
var step3 = { x: step2.x * R2D, y: step2.y * R2D };
console.log('After R2D (degrees):', step3);

console.log('');
console.log('=== Same for proj4 string ===');
console.log('Proj4 to_meter:', pProj.oProj.to_meter);
var step1p = { x: pt.x, y: pt.y };
console.log('After to_meter (skipped):', step1p);
var step2p = pProj.oProj.inverse(step1p);
console.log('After inverse (radians):', step2p);
var step3p = { x: step2p.x * R2D, y: step2p.y * R2D };
console.log('After R2D (degrees):', step3p);
" 2>&1

